<script setup lang="ts">
import { computed } from "vue";
import File from "~/components/icons/File/index.vue";
import Loading from "~/components/icons/Loading/index.vue";
import { isEmpty } from "~/utils/ui";

const props = defineProps({
  id: {
    type: String,
    default: "",
  },
  type: {
    type: String as () => "button" | "submit" | "reset" | undefined,
    default: "button",
  },
  label: {
    type: [String, Object as () => null],
    default: null,
  },
  title: {
    type: String,
    default: "",
  },
  subtitle: {
    type: String,
    default: "",
  },
  progressPercentage: {
    type: String,
    default: 0,
  },
  disabled: {
    type: Boolean,
    default: false,
  },
  loading: {
    type: Boolean,
    default: false,
  },
  color: {
    type: String as () =>  'primary' | 'success' | 'info' | 'warning' |'error',
    default: 'primary'
  }
});

const emit = defineEmits(["on-click"]);

const buttonClass = computed((): string => {
  const baseClass =
    "p-4 stroke-gray-700 border rounded-lg flex items-center justify-center transition";
  const hoverClass = props.disabled || props.loading ? "" : "hover:bg-gray-50";
  const disabled = props.disabled ? "bg-gray-100 opacity-75" : "";
  const cursor =
    props.disabled || props.loading ? "cursor-not-allowed" : "cursor-pointer";
  return `${baseClass} ${disabled} ${cursor} ${hoverClass}`;
});

const fileButtonColor = computed(() => {
  return {
    stroke:`stroke-${props.color}-500`,
    bgIcon:`bg-${props.color}-100`,
    bg:`bg-${props.color}-500`,
    bgCard: `bg-${props.color}-50`,
  }
})

</script>

<template>
  <div>
    <label
      v-if="props.label"
      class="mb-1.5 text-sm font-semibold text-gray-700"
    >
      {{ props.label }}
    </label>
    <div :id="props.id" :class="buttonClass" @click="emit('on-click')">


      <Loading  class="w-6 h-6 animate-spin text-gray-200 fill-gray-400" v-if="props.loading" />


      <div v-else class="w-full flex justify-between items-center space-x-4">
        <div class="flex items-center space-x-4 max-w-[50%]">
          <slot name="prefix" />

          <div v-if="!$slots.prefix" class="rounded-full  p-[5px]" :class="fileButtonColor.bgCard">
            <div class="rounded-full  p-[5px]" :class="fileButtonColor.bgIcon">
              <File size="20"  :class="fileButtonColor.stroke" />
            </div>
          </div>

          <div class="max-w-[100%]">
            <p class="text-left text-sm font-medium text-gray-700 truncate">
              {{ props.title }}
            </p>
            <p
              v-if="!isEmpty(props.subtitle)"
              class="text-left text-sm text-gray-500 font-normal"
            >
              {{ props.subtitle }}
            </p>

            <div
              class="w-full flex flex-row justify-between"
              v-if="progressPercentage"
            >
              <div
              :class="fileButtonColor.bgIcon"
                class="w-full h-2  bg-opacity-20 rounded-full my-auto mr-4"
              >
                <div
                :class="fileButtonColor.bg"
                  class="w-full h-2  rounded-full"
                  :style="`width: ${progressPercentage}%`"
                />
              </div>
              <span class="font-normal"> {{ progressPercentage }}% </span>
            </div>
          </div>
        </div>

        <div>
          <slot name="suffix" />
        </div>
      </div>
    </div>
  </div>
</template>

<style scoped></style>
~/utils/ui